import { EnhancedSkillData, SkillCategory } from '@/types';

const CZECH_REGIONS = ['Praha', 'Středočeský', 'Jihočeský', 'Plzeňský', 'Karlovarský', 'Ústecký', 'Liberecký', 'Královéhradecký', 'Pardubický', 'Vysočina', 'Jihomoravský', 'Olomoucký', 'Zlínský', 'Moravskoslezský'] as const;

const generateGeographicDemand = (baseRegion: string): Record<string, number> => {
  const baseIndex = CZECH_REGIONS.indexOf(baseRegion);
  return CZECH_REGIONS.reduce((acc, region, index) => {
    const diff = Math.abs(index - baseIndex);
    const demand = Math.max(40, 100 - (diff * 10) + (Math.random() * 10 - 5));
    acc[region] = Math.round(demand);
    return acc;
  }, {} as Record<string, number>);
};

type ModuleData = { title: string; description: string; duration: number };
type ResourceInput = { name: string; url: string; type: 'course' | 'doc' | 'video' | 'book' | 'article' | 'software' | 'certification' | 'platform' | 'community' | 'resource' };
type AssessmentInput = { type: 'quiz' | 'project' | 'interview' | 'certification'; questions: number; duration: number; passingScore: number; topics: string[] };

const createSkill = (
  id: string,
  name: string,
  category: SkillCategory,
  description: string,
  icon: string,
  iconColor: string,
  tags: string[],
  salaryRange: { junior: number; mid: number; senior: number; lead: number },
  demandIndex: number,
  difficultyToLearn: 1 | 2 | 3 | 4 | 5,
  relatedSkills: string[],
  assessment?: AssessmentInput,
  resources?: ResourceInput[],
  projects?: ModuleData[]
): EnhancedSkillData => ({
  id,
  name,
  slug: id,
  category,
  subcategory: category,
  proficiency: 'Intermediate',
  description,
  longDescription: description,
  icon,
  iconColor,
  tags,
  relatedSkills,
  prerequisites: [],
  dependencies: [],
  weight: { frontend: 0.5, backend: 0.5, fullstack: 0.5, datascience: 0.5, cybersecurity: 0.5, devops: 0.5, mobile: 0.5, ai_ml: 0.5, design: 0.5, product: 0.5, marketing: 0.5, management: 0.5 },
  marketData: {
    demandIndex,
    trend: 'rising',
    growthRate: 10,
    salaryRange,
    geographicDemand: generateGeographicDemand('Praha'),
    topCompanies: ['Various companies'],
    jobPostingsCount: Math.round(demandIndex * 20),
    competitionLevel: 'medium',
    difficultyToLearn,
    timeToProficiency: difficultyToLearn === 1 ? '1-3 months' : difficultyToLearn === 2 ? '3-6 months' : difficultyToLearn === 3 ? '6-12 months' : difficultyToLearn === 4 ? '12-18 months' : '18-24 months',
    industryAdoption: 70,
    automationRisk: 15,
    futureOutlook: 'excellent'
  },
  certifications: [],
  assessment: assessment || { type: 'quiz', questions: 30, duration: 30, passingScore: 70, topics: ['Core concepts', 'Best practices', 'Tools'] },
  resources: (resources || []).map(r => ({ name: r.name, url: r.url, type: r.type as 'repo' | 'doc' | 'video' | 'design' | 'book' })),
  projects: (projects || []).map(p => ({ title: p.title, difficulty: difficultyToLearn as 1 | 2 | 3 | 4 | 5, description: p.description, outcomes: [`Master ${p.title}`, 'Apply in real projects'] })),
  careerPaths: ['frontend', 'backend', 'fullstack'],
  alternativeNames: [name],
  synonyms: [],
  languages: ['English', 'Czech'],
  tools: [],
  frameworks: [],
  platforms: ['All platforms']
});

